INSERT INTO curso (id,titulo,resumo,descricao,nivel,categoria,duracao_min,ordem,publicado) VALUES ('a1000000-0000-4000-8000-000000000008','Módulo 08, Peixes Comunitários','Os peixes mais populares para começar, e como montar um comunitário harmônico.','Tetras, rasboras, danios, barbos e arco-íris: quem são, como cuidar e como combiná-los sem brigas.','iniciante','Trilha 3 · Espécies',40,8,true);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2080000-0000-4000-8000-000000000001','a1000000-0000-4000-8000-000000000008','Tetras','<p>Os <b>tetras</b> são pequenos cardumeiros sul-americanos, coloridos e pacíficos, perfeitos para iniciantes. Neon, cardinal e imperador estão entre os mais queridos.</p>
<p>Vivem melhor em <b>cardumes de 8 ou mais</b>, o que reduz o estresse e realça as cores. Preferem água levemente ácida a neutra e boa vegetação.</p>
<div class="destaque">💡 <b>Ponto-chave:</b> Tetra feliz é tetra em cardume. Poucos indivíduos ficam medrosos, apagados e brigam mais.</div>
<a class="aquabook" href="/aquabook.html?especie=neon-cardinal">📖 Ver o Neon-cardinal no Aquabook</a>',1);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2080000-0000-4000-8000-000000000002','a1000000-0000-4000-8000-000000000008','Rasboras','<p>As <b>rasboras</b> são cardumeiros asiáticos, ainda menores e muito pacíficos. A rasbora-arlequim e a galaxy são clássicas em aquários plantados.</p>
<p>Assim como os tetras, brilham em <b>grupos grandes</b> e em água macia e levemente ácida.</p>
<div class="destaque">💡 <b>Ponto-chave:</b> Rasboras são ideais para nano aquários plantados: pequenas, calmas e deslumbrantes em cardume.</div>
<a class="aquabook" href="/aquabook.html?especie=rasbora-arlequim">📖 Ver a Rasbora-arlequim no Aquabook</a>',2);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2080000-0000-4000-8000-000000000003','a1000000-0000-4000-8000-000000000008','Danios','<p>Os <b>danios</b> (como o danio-zebra) são peixes ágeis, extremamente resistentes e ativos, ótimos para quem está começando e para ajudar na ciclagem.</p>
<p>Toleram uma ampla faixa de temperatura e são muito rápidos, então combinam melhor com peixes de energia parecida.</p>
<div class="destaque">💡 <b>Ponto-chave:</b> Danios são "à prova de iniciante", mas muito elétricos: evite juntá-los a peixes lentos ou tímidos.</div>
<a class="aquabook" href="/aquabook.html?especie=danio-zebra">📖 Ver o Danio-zebra no Aquabook</a>',3);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2080000-0000-4000-8000-000000000004','a1000000-0000-4000-8000-000000000008','Barbos','<p>Os <b>barbos</b> são cardumeiros vivazes e coloridos. O barbo-sumatra é famoso, mas tem fama de "beliscador de nadadeiras" quando mantido em grupo pequeno.</p>
<p>Em <b>cardumes grandes</b>, direcionam essa energia entre si e incomodam menos os vizinhos.</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Barbo-sumatra.png" alt="Barbo-sumatra" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Barbo-sumatra</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Barbo-cereja.png" alt="Barbo-cereja" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Barbo-cereja</div></div></div></figure>
<div class="alerta">⚠️ <b>Atenção:</b> Barbo-sumatra em grupo pequeno persegue peixes de nadadeiras longas, como o Betta. Mantenha 8 ou mais.</div>
<a class="aquabook" href="/aquabook.html?especie=barbo-sumatra">📖 Ver o Barbo-sumatra no Aquabook</a>',4);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2080000-0000-4000-8000-000000000005','a1000000-0000-4000-8000-000000000008','Arco-íris','<p>Os <b>peixes arco-íris</b> (rainbowfish) são um pouco maiores, muito pacíficos e ganham cores intensas quando adultos e bem alimentados.</p>
<p>Gostam de espaço para nadar e de estar em grupo. São uma excelente opção para comunitários de médio porte.</p>
<div class="destaque">💡 <b>Ponto-chave:</b> A cor do arco-íris "acende" com a maturidade e o cardume: filhotes na loja enganam, o adulto é espetacular.</div>
<a class="aquabook" href="/aquabook.html?especie=peixe-arco-iris-boesemani">📖 Ver o Arco-íris no Aquabook</a>',5);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2080000-0000-4000-8000-000000000006','a1000000-0000-4000-8000-000000000008','Compatibilidade','<p>Montar um comunitário é equilibrar <b>temperamento, porte e faixa de água</b>. Junte peixes de energia e tamanho parecidos, e respeite os cardumes.</p>
<p>Regras de ouro: nada que caiba na boca de outro; evite misturar peixes muito lentos com muito elétricos; e não superlote.</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">🤝</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Comunitário harmônico</text>
<circle cx="160" cy="72" r="6" fill="#0E7490"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">Mesma faixa de água</text><circle cx="160" cy="112" r="6" fill="#22C55E"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Portes compatíveis</text><circle cx="160" cy="152" r="6" fill="#EAB308"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">Respeite os cardumes</text>
</svg></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Antes de comprar, cheque as 38 incompatibilidades do Aquabook. Prevenir briga é mais fácil que separar peixe.</div>
<a class="aquabook" href="/aquabook.html">📖 Conferir compatibilidades no Aquabook</a>',6);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3080000-0000-4000-8000-000000000001','a1000000-0000-4000-8000-000000000008','Qual a melhor forma de manter tetras e rasboras?','["Sozinhos","Em casais","Em cardumes de 8 ou mais","Com peixes grandes"]',2,'Cardumes grandes reduzem estresse e realçam as cores.',1);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3080000-0000-4000-8000-000000000002','a1000000-0000-4000-8000-000000000008','O barbo-sumatra em grupo pequeno tende a:','["Ficar escondido","Beliscar nadadeiras alheias","Parar de comer","Mudar de cor"]',1,'Em grupo pequeno persegue nadadeiras longas.',2);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3080000-0000-4000-8000-000000000003','a1000000-0000-4000-8000-000000000008','Uma regra de ouro da compatibilidade é:','["Misturar tudo","Nada que caiba na boca de outro","Só um peixe por espécie","Água sempre ácida"]',1,'Se cabe na boca, vira alimento; evite grandes diferenças de porte.',3);

INSERT INTO curso (id,titulo,resumo,descricao,nivel,categoria,duracao_min,ordem,publicado) VALUES ('a1000000-0000-4000-8000-000000000009','Módulo 09, Ciclídeos','Os peixes mais inteligentes e territoriais do hobby.','Africanos, americanos, discos, acarás e escalares: personalidade forte, cuidado parental e territorialidade.','intermediario','Trilha 3 · Espécies',45,9,true);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2090000-0000-4000-8000-000000000001','a1000000-0000-4000-8000-000000000009','Ciclídeos africanos','<p>Os <b>ciclídeos africanos</b> (dos lagos Malawi e Tanganyika) são coloridos e ativos, mas <b>territoriais</b>. Vivem em água dura e alcalina, bem diferente dos sul-americanos.</p>
<p>Costuma-se mantê-los em <b>superlotação controlada</b>, para diluir a agressividade, com muitas rochas formando territórios.</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Ciclideo-joia.png" alt="Ciclídeo-joia" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Ciclídeo-joia</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Kribensis.jfif" alt="Kribensis" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Kribensis</div></div></div></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Africanos pedem água dura e alcalina. Não os misture com peixes de água mole, como discos e tetras.</div>
<a class="aquabook" href="/aquabook.html?especie=ciclideo-joia">📖 Ver ciclídeos no Aquabook</a>',1);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2090000-0000-4000-8000-000000000002','a1000000-0000-4000-8000-000000000009','Ciclídeos americanos','<p>Os <b>ciclídeos americanos</b> vão dos pequenos e pacíficos (apistogramas, ramirezi) aos gigantes cheios de personalidade (oscar, jack dempsey).</p>
<p>Muitos reconhecem o dono, remexem o layout e exigem aquários maiores e filtragem reforçada por serem "sujões".</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Oscar.png" alt="Oscar" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Oscar</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Severum.png" alt="Severum" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Severum</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Ramirezi.png" alt="Ramirezi" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Ramirezi</div></div></div></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> O Oscar cresce muito e produz muita sujeira: precisa de aquário grande e filtragem de sobra.</div>
<a class="aquabook" href="/aquabook.html?especie=oscar">📖 Ver o Oscar no Aquabook</a>',2);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2090000-0000-4000-8000-000000000003','a1000000-0000-4000-8000-000000000009','Discos','<p>O <b>disco</b> é chamado de "rei do aquário": majestoso, mas exigente. Pede água quente (28 a 30 °C), muito macia, e qualidade impecável.</p>
<p>É sensível e social: vive melhor em grupo e sofre com estresse e parâmetros instáveis. Recomendado para aquaristas com alguma experiência.</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Acara-disco.png" alt="Disco" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Disco</div></div></div></figure>
<div class="alerta">⚠️ <b>Atenção:</b> Disco não perdoa descuido: temperatura alta e estável, água macia e trocas frequentes são obrigatórias.</div>
<a class="aquabook" href="/aquabook.html?especie=acara-disco">📖 Ver o Disco no Aquabook</a>',3);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2090000-0000-4000-8000-000000000004','a1000000-0000-4000-8000-000000000009','Acarás','<p>Os <b>acarás</b> reúnem várias espécies sul-americanas de porte médio, geralmente mais tolerantes que o disco. O acará-azul e o bandeira são populares.</p>
<p>Têm forte instinto parental e podem ficar territoriais na reprodução, mas em geral convivem bem em aquários espaçosos.</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Acara-azul.jfif" alt="Acará-azul" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Acará-azul</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Acara-bandeira.png" alt="Acará-bandeira" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Acará-bandeira</div></div></div></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Acarás são um ótimo "primeiro ciclídeo": personalidade forte, porém mais tolerantes que os discos.</div>
<a class="aquabook" href="/aquabook.html?especie=acara-azul">📖 Ver os Acarás no Aquabook</a>',4);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2090000-0000-4000-8000-000000000005','a1000000-0000-4000-8000-000000000009','Escalares','<p>O <b>escalar</b> (acará-bandeira) é o ciclídeo mais icônico dos comunitários: elegante, de corpo alto e nadadeiras longas.</p>
<p>É pacífico quando jovem, mas fica territorial na reprodução. Cuidado ao juntá-lo com peixes muito pequenos (podem virar alimento) ou beliscadores (que rasgam suas nadadeiras).</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Acara-bandeira.png" alt="Escalar" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Escalar</div></div></div></figure>
<div class="alerta">⚠️ <b>Atenção:</b> Escalar come neons pequenos e sofre com barbos-sumatra. Escolha bem os companheiros de aquário.</div>
<a class="aquabook" href="/aquabook.html?especie=acara-bandeira">📖 Ver o Escalar no Aquabook</a>',5);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2090000-0000-4000-8000-000000000006','a1000000-0000-4000-8000-000000000009','Territorialidade','<p>A <b>territorialidade</b> é a marca dos ciclídeos. Eles defendem áreas, especialmente ao reproduzir, e reorganizam pedras e plantas ao seu gosto.</p>
<p>Estratégias para reduzir conflitos: aquário amplo, quebra da linha de visão com rochas e troncos, e grupos adequados a cada espécie.</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">🪨</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Reduzir conflitos</text>
<circle cx="160" cy="72" r="6" fill="#0E7490"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">Aquário amplo</text><circle cx="160" cy="112" r="6" fill="#22C55E"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Quebre a linha de visão</text><circle cx="160" cy="152" r="6" fill="#EAB308"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">Territórios com rochas</text>
</svg></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Estrutura no layout (pedras, troncos) cria territórios e "paredes", diminuindo muito a briga entre ciclídeos.</div>
<a class="aquabook" href="/aquabook.html">📖 Explorar ciclídeos no Aquabook</a>',6);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3090000-0000-4000-8000-000000000001','a1000000-0000-4000-8000-000000000009','Ciclídeos africanos preferem água:','["Mole e ácida","Dura e alcalina","Salgada","Fria"]',1,'Vêm de lagos de água dura e alcalina.',1);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3090000-0000-4000-8000-000000000002','a1000000-0000-4000-8000-000000000009','O disco é indicado para quem:','["Nunca teve aquário","Já tem experiência","Quer baixa manutenção","Tem nano aquário"]',1,'Exige água quente, macia e estável, para aquaristas experientes.',2);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3090000-0000-4000-8000-000000000003','a1000000-0000-4000-8000-000000000009','Como reduzir a territorialidade dos ciclídeos?','["Aquário pequeno","Sem decoração","Quebrar a linha de visão com rochas","Menos filtragem"]',2,'Estruturas criam territórios e reduzem confronto.',3);

INSERT INTO curso (id,titulo,resumo,descricao,nivel,categoria,duracao_min,ordem,publicado) VALUES ('a1000000-0000-4000-8000-000000000010','Módulo 10, Peixes de Fundo','Os faxineiros do aquário e o mito do "peixe que limpa o vidro".','Corydoras, ancistrus, cascudos, otocinclus e botias: o que comem de verdade e como cuidar do fundo.','iniciante','Trilha 3 · Espécies',35,10,true);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2100000-0000-4000-8000-000000000001','a1000000-0000-4000-8000-000000000010','Corydoras','<p>As <b>corydoras</b> são pequenos bagres de fundo, dóceis e sociáveis, que vasculham o substrato em busca de restos de comida. São queridíssimas em comunitários.</p>
<p>Vivem melhor em <b>grupos de 6 ou mais</b> e em substrato fino (areia), que preserva seus barbilhões sensíveis.</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Coridora-sterbai.png" alt="Coridora-sterbai" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Coridora-sterbai</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Coridora-panda.png" alt="Coridora-panda" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Coridora-panda</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Coridora-julii.png" alt="Coridora-julii" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Coridora-julii</div></div></div></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Corydora não é "faxineira": ela come sobras, mas também precisa de ração própria. Não conte com "restos" para alimentá-la.</div>
<a class="aquabook" href="/aquabook.html?especie=coridora-sterbai">📖 Ver as Corydoras no Aquabook</a>',1);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2100000-0000-4000-8000-000000000002','a1000000-0000-4000-8000-000000000010','Ancistrus','<p>O <b>ancistrus</b> (cascudo-barbudo) é um dos melhores comedores de algas do hobby, de porte pequeno e comportamento pacífico, ideal para a maioria dos aquários.</p>
<p>Gosta de <b>troncos</b> para raspar (a celulose ajuda a digestão) e de esconderijos durante o dia.</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Cascudo-ancistrus.png" alt="Ancistrus" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Ancistrus</div></div></div></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Ancistrus adora troncos: além de abrigo, a madeira faz parte da dieta dele. Ofereça sempre um.</div>
<a class="aquabook" href="/aquabook.html?especie=cascudo-ancistrus">📖 Ver o Ancistrus no Aquabook</a>',2);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2100000-0000-4000-8000-000000000003','a1000000-0000-4000-8000-000000000010','Cascudos','<p><b>Cascudos</b> reúnem muitas espécies, de pequenas a gigantes. Cuidado com o clássico "cascudo comum", que cresce muito e pode grudar em peixes de corpo alto.</p>
<p>Pesquise a espécie antes: o porte adulto e a dieta variam enormemente entre um oto e um cascudo comum.</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Cascudo-comum.png" alt="Cascudo-comum" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Cascudo-comum</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Cascudo-zebra.jpg" alt="Cascudo-zebra" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Cascudo-zebra</div></div></div></figure>
<div class="alerta">⚠️ <b>Atenção:</b> O cascudo comum pode passar de 30 cm e "chupar" o muco de peixes lentos. Nem todo cascudo serve para qualquer aquário.</div>
<a class="aquabook" href="/aquabook.html?especie=cascudo-comum">📖 Ver os Cascudos no Aquabook</a>',3);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2100000-0000-4000-8000-000000000004','a1000000-0000-4000-8000-000000000010','Otocinclus','<p>O <b>otocinclus</b> é um mini comedor de algas, pacífico e perfeito para aquários plantados. Foca em algas marrons e diatomáceas nas folhas e vidros.</p>
<p>É sensível: só deve entrar em aquário <b>maduro</b>, com biofilme e algas para comer, e de preferência em grupo.</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">🌿</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Otocinclus</text>
<circle cx="160" cy="72" r="6" fill="#22C55E"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">Mini comedor de algas</text><circle cx="160" cy="112" r="6" fill="#EAB308"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Só em aquário maduro</text><circle cx="160" cy="152" r="6" fill="#0E7490"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">Mantenha em grupo</text>
</svg></figure>
<div class="alerta">⚠️ <b>Atenção:</b> Oto morre de fome em aquário novo e "limpo demais". Introduza apenas quando já houver biofilme e algas.</div>
<a class="aquabook" href="/aquabook.html?especie=cascudo-otocinclus">📖 Ver o Otocinclus no Aquabook</a>',4);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2100000-0000-4000-8000-000000000005','a1000000-0000-4000-8000-000000000010','Botias','<p>As <b>botias</b> (como a botia-palhaço e a kuhli) são peixes de fundo ativos e sociais, muitas famosas por comerem caramujos indesejados.</p>
<p>Precisam de <b>grupos</b> e de esconderijos. A botia-palhaço cresce bastante e pede aquários grandes na fase adulta.</p>
<div class="destaque">💡 <b>Ponto-chave:</b> Botias são sociais e brincalhonas em grupo; sozinhas ficam estressadas. A botia-palhaço engana no tamanho: cresce muito.</div>
<a class="aquabook" href="/aquabook.html?especie=botia-palhaco">📖 Ver as Botias no Aquabook</a>',5);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2100000-0000-4000-8000-000000000006','a1000000-0000-4000-8000-000000000010','Limpeza do substrato','<p>Nenhum peixe "limpa o aquário" por você. Os habitantes de fundo ajudam removendo sobras, mas a <b>matéria orgânica se acumula no substrato</b> e precisa de manutenção.</p>
<p>O <b>sifonamento</b> do fundo durante as trocas de água remove o lodo antes que ele vire amônia e nitrato.</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">🧹</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Cuidando do fundo</text>
<circle cx="160" cy="72" r="6" fill="#0E7490"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">Sifone o substrato nas trocas</text><circle cx="160" cy="112" r="6" fill="#22C55E"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Peixes de fundo só ajudam</text><circle cx="160" cy="152" r="6" fill="#EAB308"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">Evite acúmulo de lodo</text>
</svg></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Peixe de fundo é ajudante, não substituto do sifão. A limpeza do substrato continua sendo tarefa sua.</div>
<a class="aquabook" href="/aquabook.html">📖 Explorar peixes de fundo no Aquabook</a>',6);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3100000-0000-4000-8000-000000000001','a1000000-0000-4000-8000-000000000010','As corydoras devem ser mantidas:','["Sozinhas","Em grupos de 6 ou mais","Só com ciclídeos","Sem alimentação própria"]',1,'São sociáveis e precisam de grupo e de ração própria.',1);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3100000-0000-4000-8000-000000000002','a1000000-0000-4000-8000-000000000010','O otocinclus só deve entrar em aquário:','["Recém-montado","Maduro, com algas","Sem plantas","Muito iluminado"]',1,'Precisa de biofilme e algas já estabelecidos.',2);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3100000-0000-4000-8000-000000000003','a1000000-0000-4000-8000-000000000010','Sobre "peixe que limpa o aquário":','["Substitui a manutenção","Apenas ajuda; o sifão é necessário","Come todo o lodo","Dispensa trocas de água"]',1,'Eles ajudam, mas a limpeza do substrato continua sendo sua.',3);

INSERT INTO curso (id,titulo,resumo,descricao,nivel,categoria,duracao_min,ordem,publicado) VALUES ('a1000000-0000-4000-8000-000000000011','Módulo 11, Vivíparos','Os peixes que dão à luz filhotes, ideais para iniciantes.','Guppy, molly, espada, platy e endler: coloridos, resistentes e prolíficos.','iniciante','Trilha 3 · Espécies',30,11,true);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2110000-0000-4000-8000-000000000001','a1000000-0000-4000-8000-000000000011','Guppy','<p>O <b>guppy</b> é talvez o peixe mais popular do mundo: pequeno, coloridíssimo e muito fácil de manter. Os machos exibem caudas espetaculares.</p>
<p>Prefere água levemente dura e alcalina e se reproduz com enorme facilidade, dando filhotes já formados.</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">🐟</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Guppy</text>
<circle cx="160" cy="72" r="6" fill="#0E7490"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">Cores e caudas exuberantes</text><circle cx="160" cy="112" r="6" fill="#22C55E"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Fácil e resistente</text><circle cx="160" cy="152" r="6" fill="#EAB308"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">Reproduz com facilidade</text>
</svg></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Guppy multiplica rápido: comece só com machos, ou planeje o destino dos filhotes para não superlotar.</div>
<a class="aquabook" href="/aquabook.html?especie=guppy">📖 Ver o Guppy no Aquabook</a>',1);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2110000-0000-4000-8000-000000000002','a1000000-0000-4000-8000-000000000011','Molly','<p>O <b>molly</b> é um vivíparo um pouco maior, robusto e ativo. Aprecia água dura e alcalina e, em alguns casos, um leve teor de sal.</p>
<p>É pacífico, mas os machos podem ser insistentes com as fêmeas, então mantenha mais fêmeas que machos.</p>
<div class="destaque">💡 <b>Ponto-chave:</b> Mantenha 2 a 3 fêmeas para cada macho de vivíparo: isso reduz o assédio e o estresse das fêmeas.</div>
<a class="aquabook" href="/aquabook.html?especie=guppy">📖 Ver vivíparos no Aquabook</a>',2);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2110000-0000-4000-8000-000000000003','a1000000-0000-4000-8000-000000000011','Espada','<p>O <b>peixe-espada</b> (xifo) tem o macho com a característica "espada" na cauda. É ativo, resistente e um ótimo comunitário de porte médio.</p>
<p>Bom saltador: aquário sempre tampado. Aprecia espaço para nadar e água dura a levemente alcalina.</p>
<div class="alerta">⚠️ <b>Atenção:</b> Xifos pulam com facilidade. Mantenha o aquário bem tampado para evitar acidentes.</div>
<a class="aquabook" href="/aquabook.html?especie=guppy">📖 Ver vivíparos no Aquabook</a>',3);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2110000-0000-4000-8000-000000000004','a1000000-0000-4000-8000-000000000011','Platy','<p>O <b>platy</b> é o "primo redondinho" do espada: pequeno, dócil, coloridíssimo e extremamente fácil, perfeito para o primeiro aquário.</p>
<p>Convive muito bem com guppys e mollys, formando um comunitário de vivíparos alegre e resistente.</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">🎨</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Platy</text>
<circle cx="160" cy="72" r="6" fill="#22C55E"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">Muito fácil e pacífico</text><circle cx="160" cy="112" r="6" fill="#0E7490"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Ótimo para iniciantes</text><circle cx="160" cy="152" r="6" fill="#EAB308"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">Combina com guppy e molly</text>
</svg></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Platy é um dos melhores peixes para começar: bonito, calmo e tolerante a pequenos erros de manutenção.</div>
<a class="aquabook" href="/aquabook.html?especie=platy">📖 Ver o Platy no Aquabook</a>',4);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2110000-0000-4000-8000-000000000005','a1000000-0000-4000-8000-000000000011','Endler','<p>O <b>endler</b> é um parente próximo do guppy, ainda menor e com cores neon vibrantes. Perfeito para nano aquários plantados.</p>
<p>Cruza facilmente com guppys comuns, então mantenha-os separados se quiser preservar a linhagem pura.</p>
<div class="destaque">💡 <b>Ponto-chave:</b> Endler e guppy se cruzam com facilidade. Para manter a linhagem, não os misture no mesmo aquário.</div>
<a class="aquabook" href="/aquabook.html?especie=guppy">📖 Ver vivíparos no Aquabook</a>',5);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3110000-0000-4000-8000-000000000001','a1000000-0000-4000-8000-000000000011','Para reduzir o assédio às fêmeas de vivíparos:','["Só machos e uma fêmea","Mais fêmeas que machos","Um casal apenas","Sem esconderijos"]',1,'2 a 3 fêmeas por macho dilui o assédio.',1);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3110000-0000-4000-8000-000000000002','a1000000-0000-4000-8000-000000000011','Por que tampar o aquário de espadas?','["Por causa da luz","Porque pulam","Para esquentar","Para o cardume"]',1,'Xifos saltam com facilidade.',2);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3110000-0000-4000-8000-000000000003','a1000000-0000-4000-8000-000000000011','Qual vivíparo é dos melhores para iniciantes?','["Disco","Platy","Cascudo comum","Acará"]',1,'Platy é fácil, pacífico e resistente.',3);

INSERT INTO curso (id,titulo,resumo,descricao,nivel,categoria,duracao_min,ordem,publicado) VALUES ('a1000000-0000-4000-8000-000000000012','Módulo 12, Bettas','O guerreiro siamês merece um módulo só seu.','Comportamento, reprodução, doenças e a montagem ideal para o Betta splendens.','iniciante','Trilha 3 · Espécies',30,12,true);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2120000-0000-4000-8000-000000000001','a1000000-0000-4000-8000-000000000012','Comportamento','<p>O <b>Betta</b> é um peixe labiríntico: respira ar atmosférico na superfície. O macho é territorial e não tolera outro macho, daí o apelido "peixe-de-briga".</p>
<p>É inteligente e interativo, reconhece o dono e explora o ambiente. Ao contrário do mito, <b>não vive bem em copos</b>: precisa de espaço e água aquecida.</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">👑</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Betta</text>
<circle cx="160" cy="72" r="6" fill="#0E7490"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">Respira ar na superfície</text><circle cx="160" cy="112" r="6" fill="#EF4444"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Macho é territorial</text><circle cx="160" cy="152" r="6" fill="#22C55E"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">Precisa de espaço e calor</text>
</svg></figure>
<div class="alerta">⚠️ <b>Atenção:</b> Dois machos juntos brigam até a morte. E o "aquário de copo" é maus-tratos: o Betta precisa de volume, filtro e aquecedor.</div>
<a class="aquabook" href="/aquabook.html?especie=betta">📖 Ver o Betta no Aquabook</a>',1);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2120000-0000-4000-8000-000000000002','a1000000-0000-4000-8000-000000000012','Reprodução','<p>Na reprodução, o macho constrói um <b>ninho de bolhas</b> na superfície e corteja a fêmea. Após a desova, ele cuida sozinho dos ovos e alevinos.</p>
<p>É um processo fascinante, mas exige preparo: tanque separado, alimentação viva e retirada da fêmea após a desova.</p>
<div class="destaque">💡 <b>Ponto-chave:</b> O ninho de bolhas é sinal de macho saudável e maduro. A fêmea deve ser retirada logo após a desova.</div>
<a class="aquabook" href="/aquabook.html?especie=betta">📖 Ver o Betta no Aquabook</a>',2);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2120000-0000-4000-8000-000000000003','a1000000-0000-4000-8000-000000000012','Doenças','<p>Os Bettas são propensos a problemas ligados à <b>má qualidade da água</b> e ao frio: podridão de nadadeiras, íctio e distensão (hidropsia).</p>
<p>A prevenção é quase sempre a mesma: água limpa, aquecida e estável. A maioria das doenças começa por descuido de manutenção.</p>
<div class="alerta">⚠️ <b>Atenção:</b> Nadadeiras "derretendo" costumam ser fin rot por água ruim ou fria. Corrija a água antes de medicar.</div>
<a class="aquabook" href="/aquabook.html?especie=betta">📖 Ver o Betta no Aquabook</a>',3);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2120000-0000-4000-8000-000000000004','a1000000-0000-4000-8000-000000000012','Montagem ideal','<p>O Betta ideal vive em <b>aquário aquecido</b> (24 a 28 °C), com filtro de vazão suave (ele tem nadadeiras pesadas), plantas e esconderijos.</p>
<p>Um volume a partir de 10 litros já muda tudo em relação ao copo. Tampa é obrigatória: ele salta.</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">🏠</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Montagem do Betta</text>
<circle cx="160" cy="72" r="6" fill="#22C55E"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">Aquecido, 24 a 28 °C</text><circle cx="160" cy="112" r="6" fill="#0E7490"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Filtro de vazão suave</text><circle cx="160" cy="152" r="6" fill="#EAB308"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">Plantas, esconderijos e tampa</text>
</svg></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Vazão forte cansa o Betta. Prefira filtro suave, muitas plantas e um teto (labirinto precisa da superfície calma).</div>
<a class="aquabook" href="/aquabook.html?especie=betta">📖 Ver o Betta no Aquabook</a>',4);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3120000-0000-4000-8000-000000000001','a1000000-0000-4000-8000-000000000012','O Betta é um peixe labiríntico, o que significa que:','["Vive em labirintos","Respira ar na superfície","Não precisa de água","Muda de cor"]',1,'Respira ar atmosférico; precisa de acesso à superfície.',1);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3120000-0000-4000-8000-000000000002','a1000000-0000-4000-8000-000000000012','Manter Betta em copo é:','["Ideal","Maus-tratos, precisa de espaço e calor","Recomendado","Bom para reprodução"]',1,'Ele precisa de volume, filtro e aquecedor.',2);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3120000-0000-4000-8000-000000000003','a1000000-0000-4000-8000-000000000012','Nadadeiras "derretendo" no Betta geralmente indicam:','["Idade","Fin rot por água ruim/fria","Fome","Excesso de luz"]',1,'Corrija a qualidade e a temperatura da água.',3);

INSERT INTO curso (id,titulo,resumo,descricao,nivel,categoria,duracao_min,ordem,publicado) VALUES ('a1000000-0000-4000-8000-000000000013','Módulo 13, Peixes Marinhos','Os habitantes do reef, do palhaço aos majestosos anjos.','Palhaços, gobies, blennies, firefish, dottybacks, cirurgiões, anjos, borboletas e wrasses: quem convive bem no marinho.','avancado','Trilha 3 · Espécies',55,13,true);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2130000-0000-4000-8000-000000000001','a1000000-0000-4000-8000-000000000013','Palhaços','<p>O <b>peixe-palhaço</b> é o marinho mais icônico. Resistente para o padrão do hobby, é ótimo para iniciar no reef. Vive em harmonia com anêmonas, mas não depende delas.</p>
<p>Casais formam um par estável; evite dois machos dominantes de espécies agressivas (como o maroon) no mesmo tanque pequeno.</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Palhaco-ocellaris.png" alt="Palhaço-ocellaris" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Palhaço-ocellaris</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Palhaco-tomate.png" alt="Palhaço-tomate" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Palhaço-tomate</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Palhaco-maroon.png" alt="Palhaço-maroon" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Palhaço-maroon</div></div></div></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> O palhaço-ocellaris é o mais dócil e indicado para começar. O maroon é lindo, porém bem mais territorial.</div>
<a class="aquabook" href="/aquabook.html?especie=palhaco-ocellaris">📖 Ver o Palhaço no Aquabook</a>',1);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2130000-0000-4000-8000-000000000002','a1000000-0000-4000-8000-000000000013','Gobies e Firefish','<p>Os <b>gobies</b> são pequenos, pacíficos e cheios de personalidade. Muitos formam parceria com camarões (o goby "vigia", o camarão cava a toca).</p>
<p>O <b>firefish</b> é um goby elegante e tímido, ótimo para nano reefs, mas pulador: exige tampa.</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Gobi-mandarim.png" alt="Gobi-mandarim" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Gobi-mandarim</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Gobi-firefish.png" alt="Firefish" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Firefish</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Gobi-watchman-amarelo.png" alt="Goby-watchman" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Goby-watchman</div></div></div></figure>
<div class="alerta">⚠️ <b>Atenção:</b> Firefish e muitos gobies saltam quando assustados. Tampe o aquário. O mandarim exige aquário maduro cheio de copépodes.</div>
<a class="aquabook" href="/aquabook.html?especie=gobi-mandarim">📖 Ver os Gobies no Aquabook</a>',2);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2130000-0000-4000-8000-000000000003','a1000000-0000-4000-8000-000000000013','Blennies e Dottybacks','<p>Os <b>blennies</b> são simpáticos "cara de sapo" que empoleiram nas rochas; alguns ajudam a controlar algas. Os <b>dottybacks</b> são coloridos, porém territoriais.</p>
<p>Adicione o dottyback por último, pois ele defende cavernas com firmeza contra recém-chegados.</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">🪨</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Blennies e Dottybacks</text>
<circle cx="160" cy="72" r="6" fill="#22C55E"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">Blenny: come algas, dócil</text><circle cx="160" cy="112" r="6" fill="#EAB308"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Dottyback: colorido, territorial</text><circle cx="160" cy="152" r="6" fill="#0E7490"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">Adicione o dottyback por último</text>
</svg></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Ordem de introdução importa no reef: peixes territoriais entram por último, quando os outros já têm território.</div>
<a class="aquabook" href="/aquabook.html">📖 Explorar marinhos no Aquabook</a>',3);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2130000-0000-4000-8000-000000000004','a1000000-0000-4000-8000-000000000013','Cirurgiões e Tangs','<p>Os <b>cirurgiões</b> (tangs) são nadadores incansáveis e grandes comedores de algas. Têm um "bisturi" afiado na base da cauda, daí o nome.</p>
<p>Precisam de <b>muito espaço para nadar</b> e são propensos a íctio quando estressados. Não são peixes para aquários pequenos.</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Cirurgiao-amarelo.png" alt="Cirurgião-amarelo" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Cirurgião-amarelo</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Cirurgiao-naso.png" alt="Cirurgião-naso" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Cirurgião-naso</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Cirurgiao-patela.png" alt="Cirurgião-patela" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Cirurgião-patela</div></div></div></figure>
<div class="alerta">⚠️ <b>Atenção:</b> Tangs exigem aquários grandes e são sensíveis ao íctio marinho. Estresse e pouco espaço adoecem esses peixes.</div>
<a class="aquabook" href="/aquabook.html?especie=cirurgiao-patela">📖 Ver os Cirurgiões no Aquabook</a>',4);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2130000-0000-4000-8000-000000000005','a1000000-0000-4000-8000-000000000013','Anjos e Borboletas','<p>Os <b>anjos</b> e <b>borboletas</b> estão entre os mais deslumbrantes do mar. Os anjos-anões são mais viáveis; os grandes exigem sistemas enormes.</p>
<p>Muitos "beliscam" corais e invertebrados, então nem todos são <b>reef-safe</b>. Pesquise cada espécie antes de introduzir num reef.</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Anjo-imperador.png" alt="Anjo-imperador" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Anjo-imperador</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Anjo-chama.png" alt="Anjo-chama" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Anjo-chama</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Borboleta-copperband.png" alt="Borboleta-copperband" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Borboleta-copperband</div></div></div></figure>
<div class="alerta">⚠️ <b>Atenção:</b> Muitos anjos e borboletas não são reef-safe: podem comer corais e invertebrados. Confirme antes de colocar no reef.</div>
<a class="aquabook" href="/aquabook.html?especie=anjo-coral">📖 Ver os Anjos no Aquabook</a>',5);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2130000-0000-4000-8000-000000000006','a1000000-0000-4000-8000-000000000013','Wrasses','<p>Os <b>wrasses</b> (bodiões) são coloridos, ativos e muitos são úteis: comem parasitas e pragas do reef. Alguns dormem enterrados na areia.</p>
<p>A maioria é pacífica, mas há espécies maiores e predadoras. Como saltam bastante, tampa é essencial.</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Bodiao-limpador.png" alt="Bodião-limpador" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Bodião-limpador</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Bodiao-melanurus.png" alt="Bodião-melanurus" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Bodião-melanurus</div></div></div></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Muitos wrasses são "faxineiros" do reef, comendo pragas. Precisam de areia para dormir e de aquário bem tampado.</div>
<a class="aquabook" href="/aquabook.html">📖 Explorar wrasses no Aquabook</a>',6);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3130000-0000-4000-8000-000000000001','a1000000-0000-4000-8000-000000000013','Qual palhaço é o mais indicado para iniciantes?','["Maroon","Ocellaris","Nenhum","Todos agressivos"]',1,'O ocellaris é o mais dócil.',1);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3130000-0000-4000-8000-000000000002','a1000000-0000-4000-8000-000000000013','Peixes territoriais no reef devem ser introduzidos:','["Primeiro","Por último","Sozinhos","Nunca"]',1,'Entram por último, quando os outros já têm território.',2);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3130000-0000-4000-8000-000000000003','a1000000-0000-4000-8000-000000000013','Sobre anjos e borboletas no reef:','["Todos são reef-safe","Muitos comem corais","Não comem nada","São pacíficos com corais"]',1,'Vários não são reef-safe; pesquise antes.',3);

INSERT INTO curso (id,titulo,resumo,descricao,nivel,categoria,duracao_min,ordem,publicado) VALUES ('a1000000-0000-4000-8000-000000000014','Módulo 14, Corais','Do coral mole resistente ao exigente SPS, entenda os três grandes grupos.','Corais moles, LPS e SPS: fluxo, luz e estabilidade que cada grupo pede.','avancado','Trilha 3 · Espécies',50,14,true);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2140000-0000-4000-8000-000000000001','a1000000-0000-4000-8000-000000000014','Corais Moles','<p>Os <b>corais moles</b> (zoanthus, discosoma, ricordea, leather) não formam esqueleto rígido e são os mais <b>tolerantes</b>, ideais para começar no reef.</p>
<p>Aceitam luz e fluxo moderados e perdoam pequenas oscilações de parâmetros. Muitos se espalham rápido, colorindo as rochas.</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Zoanthus.png" alt="Zoanthus" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Zoanthus</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Ricordea-florida.png" alt="Ricordea" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Ricordea</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Kenya-tree.png" alt="Kenya tree" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Kenya tree</div></div></div></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Comece o reef pelos corais moles: baratos, resistentes e tolerantes, são a melhor escola antes dos LPS e SPS.</div>
<a class="aquabook" href="/aquabook.html?especie=zoanthus">📖 Ver corais moles no Aquabook</a>',1);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2140000-0000-4000-8000-000000000002','a1000000-0000-4000-8000-000000000014','Corais LPS','<p>Os <b>LPS</b> (large polyp stony, como euphyllia, duncan, acan e blastomussa) formam esqueleto e têm pólipos carnudos e vistosos.</p>
<p>Pedem luz e fluxo <b>moderados</b> e alcalinidade estável. Muitos têm tentáculos urticantes: dê espaço entre colônias para evitar "guerra química".</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Euphyllia-martelo.png" alt="Euphyllia" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Euphyllia</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Blastomussa.png" alt="Blastomussa" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Blastomussa</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Acanthastrea.png" alt="Acan" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Acan</div></div></div></figure>
<div class="alerta">⚠️ <b>Atenção:</b> LPS "brigam": tentáculos urticantes queimam vizinhos. Deixe espaço entre as colônias no layout.</div>
<a class="aquabook" href="/aquabook.html?especie=euphyllia-martelo">📖 Ver corais LPS no Aquabook</a>',2);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2140000-0000-4000-8000-000000000003','a1000000-0000-4000-8000-000000000014','Corais SPS','<p>Os <b>SPS</b> (small polyp stony, como acropora, montipora, stylophora e pocillopora) são os "reis do reef": crescem em galhos e exibem cores incríveis.</p>
<p>São os mais <b>exigentes</b>: luz forte, fluxo intenso e, acima de tudo, <b>estabilidade absoluta</b> de KH, cálcio e magnésio. Só para aquaristas experientes.</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Acropora.png" alt="Acropora" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Acropora</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Porites.png" alt="Porites" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Porites</div></div></div></figure>
<div class="alerta">⚠️ <b>Atenção:</b> SPS não perdoam oscilação: uma variação brusca de KH pode causar RTN e perder a colônia em horas.</div>
<a class="aquabook" href="/aquabook.html?especie=acropora">📖 Ver corais SPS no Aquabook</a>',3);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3140000-0000-4000-8000-000000000001','a1000000-0000-4000-8000-000000000014','Qual grupo de coral é o mais indicado para começar?','["SPS","LPS","Corais moles","Nenhum"]',2,'Moles são tolerantes e resistentes.',1);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3140000-0000-4000-8000-000000000002','a1000000-0000-4000-8000-000000000014','Os SPS exigem, acima de tudo:','["Pouca luz","Estabilidade de KH/Ca/Mg","Água mole","Baixo fluxo"]',1,'Estabilidade dos parâmetros é essencial para SPS.',2);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3140000-0000-4000-8000-000000000003','a1000000-0000-4000-8000-000000000014','Por que dar espaço entre colônias de LPS?','["Estética","Tentáculos urticantes","Falta de luz","Para o fluxo"]',1,'Eles se queimam com tentáculos urticantes.',3);

INSERT INTO curso (id,titulo,resumo,descricao,nivel,categoria,duracao_min,ordem,publicado) VALUES ('a1000000-0000-4000-8000-000000000015','Módulo 15, Invertebrados','Um mundo negligenciado: camarões, caramujos e a fauna do fundo do mar.','Camarões, caramujos, estrelas, ofiúros, pepinos, ouriços e caranguejos, e por que são sensíveis.','intermediario','Trilha 3 · Espécies',40,15,true);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2150000-0000-4000-8000-000000000001','a1000000-0000-4000-8000-000000000015','Camarões','<p>Os <b>camarões</b> são estrelas dos plantados (red cherry, amano) e faxineiros do reef (camarão-limpador). Comem algas, sobras e biofilme.</p>
<p>São muito sensíveis a <b>cobre</b> e a mudanças bruscas de parâmetros. Precisam de aclimatação lenta e de água estável.</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Camarao-limpador.png" alt="Camarão-limpador" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Camarão-limpador</div></div></div></figure>
<div class="alerta">⚠️ <b>Atenção:</b> Cobre é letal para camarões. Nunca use medicamentos com cobre num aquário que tenha invertebrados.</div>
<a class="aquabook" href="/aquabook.html?especie=camarao-limpador">📖 Ver os Camarões no Aquabook</a>',1);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2150000-0000-4000-8000-000000000002','a1000000-0000-4000-8000-000000000015','Caramujos','<p>Os <b>caramujos</b> podem ser aliados (neritina, que come algas sem se reproduzir na água doce) ou pragas (physas que se multiplicam sem controle).</p>
<p>A explosão de caramujos-praga quase sempre denuncia <b>excesso de comida</b> no aquário.</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">🐌</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Caramujos</text>
<circle cx="160" cy="72" r="6" fill="#22C55E"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">Neritina: come algas, aliada</text><circle cx="160" cy="112" r="6" fill="#EAB308"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Physa: praga se há excesso de ração</text><circle cx="160" cy="152" r="6" fill="#0E7490"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">Controle a alimentação</text>
</svg></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Não combata caramujo-praga com veneno: corrija a causa (excesso de ração) e a população cai sozinha.</div>
<a class="aquabook" href="/aquabook.html">📖 Explorar invertebrados no Aquabook</a>',2);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2150000-0000-4000-8000-000000000003','a1000000-0000-4000-8000-000000000015','Estrelas-do-mar','<p>As <b>estrelas-do-mar</b> são belíssimas, mas exigentes: muitas espécies precisam de aquários grandes, maduros e de aclimatação muito lenta (por gotejamento).</p>
<p>Algumas são predadoras de corais ou moluscos; outras revolvem a areia. Pesquise a dieta antes de comprar.</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Estrela-do-mar-linckia.png" alt="Estrela-do-mar-linckia" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Estrela-do-mar-linckia</div></div></div></figure>
<div class="alerta">⚠️ <b>Atenção:</b> Muitas estrelas morrem por aclimatação rápida. Elas exigem gotejamento longo e sistemas estáveis e maduros.</div>
<a class="aquabook" href="/aquabook.html?especie=estrela-do-mar-linckia">📖 Ver as Estrelas no Aquabook</a>',3);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2150000-0000-4000-8000-000000000004','a1000000-0000-4000-8000-000000000015','Ofiúros','<p>Os <b>ofiúros</b> (estrelas-serpente) são faxineiros noturnos discretos: vasculham fendas atrás de sobras. A maioria é pacífica e útil no reef.</p>
<p>Evite as espécies verdes grandes, que podem predar peixes pequenos à noite.</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">⭐</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Ofiúros</text>
<circle cx="160" cy="72" r="6" fill="#0E7490"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">Faxineiros noturnos</text><circle cx="160" cy="112" r="6" fill="#22C55E"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Maioria pacífica e útil</text><circle cx="160" cy="152" r="6" fill="#EAB308"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">Evite as verdes grandes</text>
</svg></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Ofiúros são ótimos "detritívoros" escondidos, mas cuidado com a espécie verde gigante, que pode caçar peixes.</div>
<a class="aquabook" href="/aquabook.html">📖 Explorar invertebrados no Aquabook</a>',4);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2150000-0000-4000-8000-000000000005','a1000000-0000-4000-8000-000000000015','Pepinos-do-mar','<p>Os <b>pepinos-do-mar</b> processam a areia, mantendo o substrato oxigenado e limpo. São ótimos "aspiradores" do fundo.</p>
<p>Porém, alguns liberam toxinas se morrem ou são sugados por bombas, o que pode contaminar todo o aquário.</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Pepino-do-mar.png" alt="Pepino-do-mar" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Pepino-do-mar</div></div></div></figure>
<div class="alerta">⚠️ <b>Atenção:</b> Proteja as entradas das bombas: um pepino sugado e ferido pode liberar toxina e comprometer o aquário inteiro.</div>
<a class="aquabook" href="/aquabook.html">📖 Explorar invertebrados no Aquabook</a>',5);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2150000-0000-4000-8000-000000000006','a1000000-0000-4000-8000-000000000015','Ouriços','<p>Os <b>ouriços</b> são excelentes comedores de algas e raspadores de rocha. Alguns "se vestem" com pedaços de substrato para se camuflar.</p>
<p>Podem, sem querer, derrubar corais mal fixados ao circular pelas rochas. Cole bem os frags.</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">🦔</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Ouriços</text>
<circle cx="160" cy="72" r="6" fill="#22C55E"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">Ótimos contra algas</text><circle cx="160" cy="112" r="6" fill="#0E7490"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Raspam a rocha</text><circle cx="160" cy="152" r="6" fill="#EAB308"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">Podem derrubar corais soltos</text>
</svg></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Ouriço é faxineiro de rocha eficiente, mas desajeitado: fixe bem os corais para ele não derrubá-los.</div>
<a class="aquabook" href="/aquabook.html">📖 Explorar invertebrados no Aquabook</a>',6);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2150000-0000-4000-8000-000000000007','a1000000-0000-4000-8000-000000000015','Caranguejos','<p>Os <b>caranguejos</b> variam de úteis (ermitões que comem sobras e algas) a problemáticos (espécies que predam peixes e corais).</p>
<p>Os ermitões precisam de <b>conchas vazias</b> de reserva para trocar conforme crescem, senão brigam por elas.</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Ermitao-patas-azuis.JPG" alt="Ermitão-patas-azuis" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Ermitão-patas-azuis</div></div></div></figure>
<div class="alerta">⚠️ <b>Atenção:</b> Nem todo caranguejo é pacífico: alguns "hitchhikers" das rochas predam peixes à noite. Ofereça conchas extras aos ermitões.</div>
<a class="aquabook" href="/aquabook.html">📖 Explorar invertebrados no Aquabook</a>',7);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3150000-0000-4000-8000-000000000001','a1000000-0000-4000-8000-000000000015','Qual substância é letal para camarões?','["Cálcio","Cobre","Oxigênio","Magnésio"]',1,'Cobre mata invertebrados; nunca medique com cobre no tanque deles.',1);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3150000-0000-4000-8000-000000000002','a1000000-0000-4000-8000-000000000015','A explosão de caramujos-praga indica:','["Água boa","Excesso de comida","Falta de luz","pH baixo"]',1,'Sobra de ração alimenta a multiplicação.',2);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3150000-0000-4000-8000-000000000003','a1000000-0000-4000-8000-000000000015','Estrelas-do-mar exigem, na entrada:','["Aclimatação rápida","Aclimatação lenta por gotejamento","Água doce","Muita luz"]',1,'Gotejamento longo em sistema maduro.',3);

INSERT INTO curso (id,titulo,resumo,descricao,nivel,categoria,duracao_min,ordem,publicado) VALUES ('a1000000-0000-4000-8000-000000000016','Módulo 16, Plantas Aquáticas','As plantas transformam o aquário e disputam nutrientes com as algas.','Rizomas, musgos, plantas de caule, tapetes e flutuantes, além de fertilização, CO₂ e podas.','intermediario','Trilha 3 · Espécies',45,16,true);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2160000-0000-4000-8000-000000000001','a1000000-0000-4000-8000-000000000016','Rizomas','<p>As plantas de <b>rizoma</b> (anubias, microsorum, bucephalandra) são as mais fáceis: crescem devagar, aceitam pouca luz e dispensam CO₂.</p>
<p>Regra de ouro: o <b>rizoma não pode ser enterrado</b>, senão apodrece. Amarre ou cole em rochas e troncos.</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Anubias-nana.png" alt="Anubias" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Anubias</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Bucephalandra.png" alt="Bucephalandra" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Bucephalandra</div></div></div></figure>
<div class="alerta">⚠️ <b>Atenção:</b> Nunca enterre o rizoma da anubias. Fixe sobre rocha ou tronco; só as raízes ficam livres.</div>
<a class="aquabook" href="/aquabook.html?especie=anubias-nana">📖 Ver as plantas no Aquabook</a>',1);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2160000-0000-4000-8000-000000000002','a1000000-0000-4000-8000-000000000016','Musgos','<p>Os <b>musgos</b> (java, christmas) são versáteis e fáceis: crescem presos a qualquer superfície e criam refúgio para alevinos e camarões.</p>
<p>Aceitam baixa luz, mas ficam mais bonitos e compactos com boa iluminação e podas regulares.</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Musgo-de-java.png" alt="Musgo-de-java" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Musgo-de-java</div></div></div></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Musgo é o melhor amigo do aquário de camarões: abrigo, biofilme e comida para os filhotes.</div>
<a class="aquabook" href="/aquabook.html?especie=musgo-de-java">📖 Ver as plantas no Aquabook</a>',2);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2160000-0000-4000-8000-000000000003','a1000000-0000-4000-8000-000000000016','Plantas de caule','<p>As <b>plantas de caule</b> (bacopa, rotala, hygrophila) crescem rápido e para cima, ótimas para o fundo do layout e para consumir nutrientes.</p>
<p>Por crescerem depresso, são grandes aliadas contra algas, mas exigem <b>podas frequentes</b> e, em geral, mais luz e nutrientes.</p>
<figure><div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:4px 0"><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Bacopa-caroliniana.png" alt="Bacopa" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Bacopa</div></div><div style="flex:1 1 140px;max-width:200px;text-align:center"><img src="/images/especies/Hygrophila-polysperma.png" alt="Hygrophila" loading="lazy" onerror="this.parentElement.style.display=''none''" style="width:100%;height:130px;object-fit:cover;border-radius:10px;box-shadow:0 4px 12px rgba(11,42,58.12)"><div style="font-size:11.5px;color:#64748B;margin-top:5px">Hygrophila</div></div></div></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Plantas de caule de crescimento rápido "roubam" nutrientes das algas, um método natural de controle.</div>
<a class="aquabook" href="/aquabook.html">📖 Explorar plantas no Aquabook</a>',3);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2160000-0000-4000-8000-000000000004','a1000000-0000-4000-8000-000000000016','Tapetes (carpetes)','<p>As <b>plantas de tapete</b> (hemianthus, glossostigma, grama) formam o "gramado" do aquário. São lindas, porém das mais <b>exigentes</b>.</p>
<p>Geralmente precisam de <b>luz forte, CO₂ e bom substrato fértil</b> para crescer rentes e não "esticar" para cima.</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">🌱</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Plantas de tapete</text>
<circle cx="160" cy="72" r="6" fill="#22C55E"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">O "gramado" do aquário</text><circle cx="160" cy="112" r="6" fill="#EAB308"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Exigem luz forte e CO₂</text><circle cx="160" cy="152" r="6" fill="#0E7490"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">Substrato fértil</text>
</svg></figure>
<div class="alerta">⚠️ <b>Atenção:</b> Sem CO₂ e luz forte, o tapete "estica" buscando luz e não fecha. É o grupo mais exigente das plantas.</div>
<a class="aquabook" href="/aquabook.html">📖 Explorar plantas no Aquabook</a>',4);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2160000-0000-4000-8000-000000000005','a1000000-0000-4000-8000-000000000016','Plantas flutuantes','<p>As <b>flutuantes</b> (salvinia, lentilha, pistia) sombreiam, oxigenam e consomem muitos nutrientes na superfície, ajudando a combater algas.</p>
<p>Crescem muito rápido: se não controladas, tomam toda a superfície e bloqueiam a luz das plantas de baixo.</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">🍃</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Plantas flutuantes</text>
<circle cx="160" cy="72" r="6" fill="#22C55E"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">Consomem muito nutriente</text><circle cx="160" cy="112" r="6" fill="#0E7490"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Sombra e refúgio</text><circle cx="160" cy="152" r="6" fill="#EAB308"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">Controle: crescem rápido</text>
</svg></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Flutuantes são "esponjas" de nutrientes, ótimas contra algas, mas precisam de poda para não fechar a superfície.</div>
<a class="aquabook" href="/aquabook.html">📖 Explorar plantas no Aquabook</a>',5);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2160000-0000-4000-8000-000000000006','a1000000-0000-4000-8000-000000000016','Fertilização','<p>As plantas precisam de <b>macronutrientes</b> (nitrogênio, fósforo, potássio) e <b>micronutrientes</b> (ferro e traços). A fertilização repõe o que falta na coluna d''água e no substrato.</p>
<p>O segredo é o <b>equilíbrio</b> com luz e CO₂: fertilizar demais sem luz suficiente só alimenta as algas.</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">🧪</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Fertilização</text>
<circle cx="160" cy="72" r="6" fill="#0E7490"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">Macro: N, P, K</text><circle cx="160" cy="112" r="6" fill="#22C55E"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Micro: ferro e traços</text><circle cx="160" cy="152" r="6" fill="#EAB308"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">Equilíbrio com luz e CO₂</text>
</svg></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Luz, CO₂ e nutrientes formam um tripé. Exagerar num sem os outros gera algas, não plantas.</div>
<a class="aquabook" href="/aquabook.html">📖 Explorar plantas no Aquabook</a>',6);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2160000-0000-4000-8000-000000000007','a1000000-0000-4000-8000-000000000016','CO₂','<p>O <b>CO₂</b> é o combustível da fotossíntese. Em aquários muito plantados e iluminados, adicioná-lo transforma o crescimento e a cor das plantas.</p>
<p>Deve ser dosado com cuidado: <b>CO₂ em excesso</b> baixa o pH e sufoca os peixes. Ligue com a luz e desligue à noite.</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">💨</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">CO₂</text>
<circle cx="160" cy="72" r="6" fill="#22C55E"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">Combustível da fotossíntese</text><circle cx="160" cy="112" r="6" fill="#EF4444"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Excesso sufoca os peixes</text><circle cx="160" cy="152" r="6" fill="#0E7490"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">Sincronize com a luz</text>
</svg></figure>
<div class="alerta">⚠️ <b>Atenção:</b> CO₂ demais mata peixes por falta de oxigênio e queda de pH. Use temporizador e observe os peixes.</div>
<a class="aquabook" href="/aquabook.html">📖 Explorar plantas no Aquabook</a>',7);
INSERT INTO aula (id,curso_id,titulo,conteudo,ordem) VALUES ('a2160000-0000-4000-8000-000000000008','a1000000-0000-4000-8000-000000000016','Podas','<p>A <b>poda</b> mantém o layout bonito e as plantas saudáveis. Cortar estimula a ramificação e evita que as de cima sombreiem as de baixo.</p>
<p>Retire folhas velhas e apare os caules; replante os topos mais viçosos. Poda regular é o que separa um aquário "mato" de um aquário "jardim".</p>
<figure><svg viewBox="0 0 640 164" xmlns="http://www.w3.org/2000/svg">
<rect x="0" y="0" width="640" height="164" rx="14" fill="#F6F9FB"/><rect x="20" y="30" width="104" height="104" rx="20" fill="#0E7490"/>
<text x="72" y="100" text-anchor="middle" font-size="52">✂️</text>
<text x="150" y="40" font-family="Inter,sans-serif" font-weight="800" font-size="20" fill="#0B2A3A">Podas</text>
<circle cx="160" cy="72" r="6" fill="#22C55E"/><text x="178" y="77" font-family="Inter,sans-serif" font-size="15" fill="#334155">Estimula a ramificação</text><circle cx="160" cy="112" r="6" fill="#0E7490"/><text x="178" y="117" font-family="Inter,sans-serif" font-size="15" fill="#334155">Evita sombra sobre as de baixo</text><circle cx="160" cy="152" r="6" fill="#EAB308"/><text x="178" y="157" font-family="Inter,sans-serif" font-size="15" fill="#334155">Replante os topos viçosos</text>
</svg></figure>
<div class="destaque">💡 <b>Ponto-chave:</b> Poda regular é jardinagem: sem ela, até plantas fáceis viram um emaranhado que abafa a luz e acumula detritos.</div>
<a class="aquabook" href="/aquabook.html">📖 Explorar plantas no Aquabook</a>',8);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3160000-0000-4000-8000-000000000001','a1000000-0000-4000-8000-000000000016','O rizoma da anubias deve ser:','["Enterrado no substrato","Fixado sobre rocha/tronco","Cortado","Mantido seco"]',1,'Enterrar o rizoma o faz apodrecer.',1);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3160000-0000-4000-8000-000000000002','a1000000-0000-4000-8000-000000000016','As plantas de tapete geralmente exigem:','["Pouca luz","Luz forte e CO₂","Nenhum nutriente","Água salgada"]',1,'São exigentes em luz, CO₂ e substrato fértil.',2);
INSERT INTO quiz_pergunta (id,curso_id,pergunta,opcoes,correta,explicacao,ordem) VALUES ('a3160000-0000-4000-8000-000000000003','a1000000-0000-4000-8000-000000000016','O excesso de CO₂ no aquário:','["Não faz mal","Sufoca os peixes e baixa o pH","Aumenta o oxigênio","Mata as algas"]',1,'Excesso reduz oxigênio e derruba o pH.',3);

